        .replace(/\bbad\b/g, "poor")
        .trim(),
    2: (t) =>
      t
        .replace(/\bextremely\b/g, "remarkably")
        .replace(/\bexcellent\b/g, "outstanding")
        .replace(/\bpoor\b/g, "substandard")
        .trim(),
    3: (t) =>
      t
        .replace(/\bremarkably\b/g, "exceptionally")
        .replace(/\boutstanding\b/g, "exemplary")
        .trim(),
  };

  const step = Math.min(iteration ?? 1, 3);
  const refineFn = mockRefinements[step] ?? ((t: string) => t);
  const refined = refineFn(text);

  const changes: string[] = [];
  if (refined !== text) {
    changes.push(`Pass ${step}: substituted weak/filler words with stronger vocabulary`);
  } else {
    changes.push(`Pass ${step}: no further improvements found`);
  }

  return { refined, iteration: step, changes };
}

// ─────────────────────────────────────────────────────────────────────────────
// 1. schemaTask  –  the refinement worker
//    ID pattern: refine-text-${trial_id}
// ─────────────────────────────────────────────────────────────────────────────
export const refineTextTask = schemaTask({
  id: `refine-text-${TRIAL_ID}`,
  description:
    "Accepts a piece of text and returns an improved (refined) version of it. " +
    "Call this tool repeatedly to progressively enhance the quality of the text.",
  schema: RefineInputSchema,

  run: async (payload): Promise<RefineOutput> => {
    logger.info("refine-text: starting", {
      iteration: payload.iteration,
      inputLength: payload.text.length,
    });

    const result = await performRefinement(payload);

    logger.info("refine-text: complete", {
      iteration: result.iteration,
      changes: result.changes,
      outputLength: result.refined.length,
    });

    return result;
  },
});

// ─────────────────────────────────────────────────────────────────────────────
// 2. ai.tool wrapper around the schemaTask
//    This converts the schemaTask into a Vercel AI SDK `Tool` so any agent
//    that uses `generateText` / `streamText` can call it automatically.
// ─────────────────────────────────────────────────────────────────────────────
export const refineTextTool = ai.tool(refineTextTask);

// ─────────────────────────────────────────────────────────────────────────────
// 3. Parent agent task  –  the refinement loop
//    ID pattern: agent-loop-${trial_id}
//
//    The loop drives at least TWO successive refinement passes.
//    On each iteration it:
//      a. calls the refineTextTask via `tasks.triggerAndWait`
//      b. checks whether the text changed since the previous pass
//      c. stops early only when the text stabilises OR the maximum number of
//         passes is reached
// ─────────────────────────────────────────────────────────────────────────────

const AgentLoopInputSchema = z.object({
  initialText: z.string().describe("The original text to refine"),
  maxIterations: z
    .number()
    .int()
    .min(2)
    .max(10)
    .optional()
    .default(3)
    .describe("Maximum number of refinement passes (minimum 2)"),
});

type AgentLoopInput = z.infer<typeof AgentLoopInputSchema>;

export const agentLoopTask = schemaTask({
  id: `agent-loop-${TRIAL_ID}`,
  description:
    "An AI agent loop that progressively refines a piece of text by calling the " +
    `refine-text-${TRIAL_ID} tool in a loop until the text stabilises or the ` +
    "maximum number of iterations is reached.",
  schema: AgentLoopInputSchema,

  run: async (payload: AgentLoopInput) => {
    const { initialText, maxIterations } = payload;
    const MAX = Math.max(maxIterations ?? 3, 2); // always at least 2 passes

    logger.info("agent-loop: starting", { maxIterations: MAX, initialText });

    const history: Array<{
      iteration: number;
      text: string;
      changes: string[];
    }> = [{ iteration: 0, text: initialText, changes: ["(original)"] }];

    let currentText = initialText;

    for (let i = 1; i <= MAX; i++) {
      logger.info(`agent-loop: iteration ${i}/${MAX}`);

      // ── Trigger the schemaTask and wait for its result ──────────────────
      const result = await tasks.triggerAndWait<typeof refineTextTask>(
        `refine-text-${TRIAL_ID}`,
        { text: currentText, iteration: i }
      );

      if (!result.ok) {
        logger.error("agent-loop: refine-text subtask failed", {
          error: result.error,
          iteration: i,
        });
        throw new Error(
          `Refinement pass ${i} failed: ${JSON.stringify(result.error)}`
        );
      }

      const { refined, changes } = result.output;

      history.push({ iteration: i, text: refined, changes });

      logger.info(`agent-loop: iteration ${i} complete`, {
        changed: refined !== currentText,
        changes,
      });

      // ── Early-stop if text stabilised (but only after minimum 2 passes) ─
      if (refined === currentText && i >= 2) {
        logger.info("agent-loop: text stabilised – stopping early", {
          stoppedAt: i,
        });
        break;
      }

      currentText = refined;
    }

    const finalText = history[history.length - 1].text;

    logger.info("agent-loop: finished", {
      totalPasses: history.length - 1, // exclude the "original" entry
      finalLength: finalText.length,
    });

    return {
      original: initialText,
      final: finalText,
      totalPasses: history.length - 1,
      history,
    };
  },
});

